// 1. Junta TODAS as mensagens (globalmente)
const mensagens = $input.all().flatMap(item => {
  const data = item.json["REDIS 02"];

  if (Array.isArray(data)) return data;

  try {
    const parsed = JSON.parse(data);
    return Array.isArray(parsed) ? parsed : [String(data)];
  } catch {
    return [String(data)];
  }
});

const mensagem_completa = mensagens.join(" ");

// 2. DEVOLVE OS MESMOS ITEMS (preserva Telefone e pareamento)
return $input.all().map(item => ({
  json: {
    ...item.json,        // <-- mantém Telefone intacto
    mensagem_completa    // <-- adiciona o texto unificado
  }
}));

const input = query;
const [day, month, year] = input.split('/').map(Number);
const date = new Date(year, month - 1, day);
return date.toLocaleDateString('pt-BR', { weekday: 'long' });
